SQL:
SELECT Description, OutOfPocketExpense
FROM SurgicalProcedures
ORDER BY OutOfPocketExpense DESC;

SELECT Description, InsuranceCovered, OutOfPocketExpense
FROM SurgicalProcedures
ORDER BY InsuranceCovered, OutOfPocketExpense DESC;

SELECT Description, InsuranceCovered
FROM SurgicalProcedures
ORDER BY InsuranceCovered DESC;
